#!/usr/bin/env node
/**
 * parse-strategy.mjs
 *
 * Reads a VideoStrategy JSON file (generated by Claude/Perplexity using the §6a prompt)
 * and ingests it into the campaign:
 *   - Writes one script .md per video  → campaigns/{id}/scripts/{vid}_{format}.md
 *   - Writes social captions .md       → campaigns/{id}/scripts/{vid}_social_captions.md
 *   - Updates campaign.json videos[]   → adds platform, targetDuration, hook, imagePrompt,
 *                                         thumbnailText, audioMood/Tempo/Feel, selectedScript
 *   - Adds audiences[] to campaign.json from strategy audiences
 *
 * The JSON may be a raw .json file or a .md file containing a ```json ... ``` block.
 *
 * Usage:
 *   node scripts/parse-strategy.mjs --campaign=001 --file=promote/campaigns/001-overture-downloader/VideoStrategy.json
 *   node scripts/parse-strategy.mjs --campaign=001 --file=promote/assets/overture-downloader_video_strategy.md
 */

import { readFile, writeFile, mkdir, readdir } from 'node:fs/promises'
import { join, dirname, extname } from 'node:path'
import { fileURLToPath } from 'node:url'

const __dirname = dirname(fileURLToPath(import.meta.url))
const ROOT      = join(__dirname, '..')

// ── Args ──────────────────────────────────────────────────────────────────────

const campaignArg = process.argv.find(a => a.startsWith('--campaign='))
const fileArg     = process.argv.find(a => a.startsWith('--file='))

if (!campaignArg || !fileArg) {
  console.error('Usage: node scripts/parse-strategy.mjs --campaign=<id> --file=<path>')
  process.exit(1)
}

const campaignId  = campaignArg.split('=')[1]
const strategyFile = join(ROOT, fileArg.split('=')[1])

// ── Load + parse strategy file ────────────────────────────────────────────────

const raw = await readFile(strategyFile, 'utf-8')

let strategy
if (extname(strategyFile) === '.json') {
  // Strip any trailing ``` that Claude may have added
  const cleaned = raw.replace(/```\s*$/, '').trim()
  strategy = JSON.parse(cleaned)
} else {
  // Extract ```json ... ``` block from markdown
  const match = raw.match(/```json\s*([\s\S]*?)```/)
  if (!match) {
    console.error('No ```json block found in the strategy file.')
    process.exit(1)
  }
  strategy = JSON.parse(match[1])
}

console.log(`\n📋  Parsing strategy: ${strategy.tool}`)
console.log(`    ${strategy.videos.length} video(s) | ${strategy.audiences.length} audience(s)\n`)

// ── Find campaign ─────────────────────────────────────────────────────────────

const campaignsDir = join(ROOT, 'promote', 'campaigns')
const entries      = await readdir(campaignsDir)
const folder       = entries.find(e => e.startsWith(`${campaignId}-`) || e === campaignId)
if (!folder) {
  console.error(`Campaign ${campaignId} not found`)
  process.exit(1)
}

const campaignDir = join(campaignsDir, folder)
const campaignPath = join(campaignDir, 'campaign.json')
const campaign    = JSON.parse(await readFile(campaignPath, 'utf-8'))
const scriptsDir  = join(campaignDir, 'scripts')
await mkdir(scriptsDir, { recursive: true })

// ── Social captions formatter ─────────────────────────────────────────────────

function formatSocialCaptions(captions) {
  const sections = []
  if (captions.youtube) {
    sections.push([
      '## YouTube',
      `**Title:** ${captions.youtube.title}`,
      '',
      '**Description:**',
      captions.youtube.description,
      '',
      `**Tags:** ${captions.youtube.tags.join(', ')}`,
    ].join('\n'))
  }
  for (const [platform, label] of [['linkedin','LinkedIn'],['twitter','Twitter/X'],['instagram','Instagram'],['tiktok','TikTok'],['reddit','Reddit']]) {
    if (captions[platform]) {
      sections.push(`## ${label}\n${captions[platform]}`)
    }
  }
  return sections.join('\n\n---\n\n')
}

// ── Process videos ────────────────────────────────────────────────────────────

const updatedVideos = []

for (const sv of strategy.videos) {
  const scriptFilename   = `${sv.id}_${sv.format}.md`
  const captionsFilename = `${sv.id}_social_captions.md`

  // Write narration script
  const scriptContent = [
    `# ${sv.format.toUpperCase()} — ${sv.id}`,
    `> Hook: ${sv.hook}`,
    `> Platform: ${sv.platform} | Duration: ${sv.targetDuration}s | Audience: ${sv.audience}`,
    '',
    sv.script,
  ].join('\n')

  await writeFile(join(scriptsDir, scriptFilename), scriptContent, 'utf-8')
  console.log(`  ✅  scripts/${scriptFilename}`)

  // Write social captions
  await writeFile(join(scriptsDir, captionsFilename), formatSocialCaptions(sv.captions), 'utf-8')
  console.log(`  ✅  scripts/${captionsFilename}`)

  // Build updated video object (merge with existing if present)
  const existing = campaign.videos?.find(v => v.id === sv.id) ?? {}

  updatedVideos.push({
    ...existing,
    id:             sv.id,
    format:         sv.format,
    platform:       sv.platform,
    targetDuration: sv.targetDuration,
    audience:       sv.audience,
    hook:           sv.hook,
    selectedScript: `${sv.id}_${sv.format}`,
    thumbnailText:  sv.thumbnailText,
    thumbnailStyle: sv.thumbnailStyle,
    imagePrompt:    sv.imagePrompt,
    audioMood:      sv.audioMood,
    audioTempo:     sv.audioTempo,
    audioFeel:      sv.audioFeel,
    // Preserve existing runtime fields
    status:         existing.status       ?? 'not-started',
    youtubeIds:     existing.youtubeIds   ?? null,
    captionsPath:   existing.captionsPath ?? `captions/${sv.id}.srt`,
    thumbnails:     existing.thumbnails   ?? {},
    musicTrack:     existing.musicTrack   ?? null,
    musicFile:      existing.musicFile    ?? null,
    voiceoverPath:  existing.voiceoverPath ?? `audio/voiceover_${sv.id}.mp3`,
  })
}

// ── Update campaign.json ──────────────────────────────────────────────────────

campaign.audiences  = strategy.audiences
campaign.videos     = updatedVideos
campaign.strategyFile = fileArg.split('=')[1]

await writeFile(campaignPath, JSON.stringify(campaign, null, 2), 'utf-8')
console.log(`\n  ✅  campaign.json updated (${updatedVideos.length} videos, ${strategy.audiences.length} audiences)`)

// ── Summary ───────────────────────────────────────────────────────────────────

console.log('\n🎬  Videos registered:')
for (const v of updatedVideos) {
  console.log(`    ${v.id}  ${v.format.padEnd(16)}  ${v.platform}  ${v.targetDuration}s  → ${v.selectedScript}`)
}

console.log(`
✅  Done. Next steps:
    1. Delete old asset files if you want to regenerate from new scripts:
       Remove-Item promote\\campaigns\\${folder}\\audio\\*.mp3
       Remove-Item promote\\campaigns\\${folder}\\images\\*.png
       Remove-Item promote\\campaigns\\${folder}\\thumbnails\\*.png
       Remove-Item promote\\campaigns\\${folder}\\captions\\*.srt
    2. Run the asset pipeline:
       node scripts/generate-assets.mjs --campaign=${campaignId}
`)
